<template>
  <ul v-if="link.sublinks" class="list-unstyled">
    <li v-for="sublink in link.sublinks" :key="sublink.id" class="d-flex align-items-center justify-content-center link-body">
      <i class="icon icon-img-unstyled" :class="sublink.icon"><img class="icon icon-img-unstyled" v-if="sublink.img" :src="loadImgFunction(sublink.img)"></i>
      <a class="link-text" :href="sublink.url" target="_blank">{{ sublink.text }}</a>
    </li>
  </ul>
</template>
  
<script>

export default {
  name: "LinkComponent",
  props: {
    link: Object,
  },
  methods:{
    loadImgFunction(value){
      try {
        return require(`@/assets/img/icon/${value}`);
      } catch (error) {
        // Em caso de erro, repasse a informação e continua
        console.error(`Erro ao carregar imagem: ${error.message}`);
      }
    }
  }
};
</script>

